+    fn test_group_by_table_alias_star() {
+        // SELECT t.* FROM ... AS t GROUP BY ... should resolve t.* correctly.
+        let conn = Connection::open(":memory:").unwrap();
+        conn.execute("CREATE TABLE employees (dept TEXT, name TEXT);")
+            .unwrap();
